def sign_request(private_key_pem: bytes, request_body: bytes) -> str:
    private_key = serialization.load_pem_private_key(private_key_pem, password=None)
    signature = private_key.sign(
        request_body,
        padding.PKCS1v15(),
        hashes.SHA256()
    )
    return signature.hex()

