    public_key = serialization.load_pem_public_key(public_key_pem)
    try:
        public_key.verify(bytes.fromhex(sig_hex), body, padding.PKCS1v15(), hashes.SHA256())
        return True
    except:
        return False

import hashlib
import json
from datetime import datetime

class LogChain:
    def __init__(self):
        self.entries = []
        self.prev_hash = '0' * 64

    def append(self, message: str):
        entry = {'ts': datetime.utcnow().isoformat(), 'msg': message, 'prev': self.prev_hash}
        entry_bytes = json.dumps(entry, sort_keys=True).encode()
        current_hash = hashlib.sha256(entry_bytes).hexdigest()
        entry['hash'] = current_hash
        self.entries.append(entry)
        self.prev_hash = current_hash

    def verify(self) -> bool:
        for i, entry in enumerate(self.entries):
            expected_hash = entry['hash']
            entry_copy = {k: v for k, v in entry.items() if k != 'hash'}
            computed = hashlib.sha256(json.dumps(entry_copy, sort_keys=True).encode()).hexdigest()
            if computed != expected_hash:
                return False
        return True

