CONFIG_KEY = bytes.fromhex('0102030405060708090a0b0c0d0e0f10')  # 硬编码
CONFIG_IV  = bytes.fromhex('a0a1a2a3a4a5a6a7a8a9aaabacadaeaf')

def encrypt_config(plaintext: str) -> bytes:
    cipher = AES.new(CONFIG_KEY, AES.MODE_CBC, CONFIG_IV)
    return cipher.encrypt(pad(plaintext.encode(), 16))

def decrypt_config(ciphertext: bytes) -> str:
    cipher = AES.new(CONFIG_KEY, AES.MODE_CBC, CONFIG_IV)
    return unpad(cipher.decrypt(ciphertext), 16).decode()

