def derive_key(password: str, salt: bytes, iterations: int = 100000, key_len: int = 32) -> bytes:
    return hashlib.pbkdf2_hmac('sha256', password.encode(), salt, iterations, dklen=key_len)

def derive_encryption_key(master_key: bytes, context: bytes, key_len: int = 16) -> bytes:
    import hmac
    prk = hmac.new(b'salt', master_key, hashlib.sha256).digest()
    okm = hmac.new(prk, context + b'\x01', hashlib.sha256).digest()
    return okm[:key_len]

from Crypto.Cipher import AES
from Crypto.Util import Counter

def stream_encrypt(key: bytes, nonce: bytes, data_chunks):
    ctr = Counter.new(128, initial_value=int.from_bytes(nonce, 'big'))
    cipher = AES.new(key, AES.MODE_CTR, counter=ctr)
    for chunk in data_chunks:
        yield cipher.encrypt(chunk)

def stream_decrypt(key: bytes, nonce: bytes, ciphertext_chunks):
    ctr = Counter.new(128, initial_value=int.from_bytes(nonce, 'big'))
    cipher = AES.new(key, AES.MODE_CTR, counter=ctr)
    for chunk in ciphertext_chunks:
        yield cipher.decrypt(chunk)

import gnupg

def encrypt_backup(gpg_home: str, backup_data: bytes, recipient_fingerprint: str) -> bytes:
    gpg = gnupg.GPG(gnupghome=gpg_home)
    encrypted = gpg.encrypt(backup_data, recipient_fingerprint, always_trust=True)
    if not encrypted.ok:
        raise ValueError(f'Encryption failed: {encrypted.status}')
    return str(encrypted).encode()

def decrypt_backup(gpg_home: str, encrypted_data: bytes, passphrase: str) -> bytes:
    gpg = gnupg.GPG(gnupghome=gpg_home)
    decrypted = gpg.decrypt(encrypted_data, passphrase=passphrase)
    return decrypted.data

