from cryptography.hazmat.primitives import hashes, serialization
from cryptography.hazmat.primitives.asymmetric import padding

def sign_package(private_key_pem: bytes, package_data: bytes) -> dict:
    private_key = serialization.load_pem_private_key(private_key_pem, None)
    signature = private_key.sign(package_data, padding.PSS(
        mgf=padding.MGF1(hashes.SHA256()),
        salt_length=padding.PSS.MAX_LENGTH
    ), hashes.SHA256())
    return {'signature': signature.hex(), 'algo': 'RSA-PSS-SHA256'}

def verify_package(pub_key_pem: bytes, pkg_data: bytes, sig_hex: str) -> bool:
    pub_key = serialization.load_pem_public_key(pub_key_pem)
    try:
        pub_key.verify(bytes.fromhex(sig_hex), pkg_data,
                       padding.PSS(mgf=padding.MGF1(hashes.SHA256()), salt_length=padding.PSS.MAX_LENGTH),
                       hashes.SHA256())
        return True
    except:
        return False

import grpc

def create_secure_channel(address: str, ca_cert: bytes, client_cert: bytes, client_key: bytes):
