import hashlib, jwt, os
from datetime import datetime, timedelta

def register(username: str, password: str) -> dict:
    salt = os.urandom(16).hex()
    pwd_hash = hashlib.sha256((salt + password).encode()).hexdigest()
    return {'username': username, 'salt': salt, 'pwd_hash': pwd_hash}

def login(user_record: dict, password: str, secret: str) -> str:
    salt = user_record['salt']
    pwd_hash = hashlib.sha256((salt + password).encode()).hexdigest()
    if pwd_hash != user_record['pwd_hash']:
        raise ValueError('Invalid credentials')
    token = jwt.encode({'sub': user_record['username'],
                         'exp': datetime.utcnow() + timedelta(hours=1)}, secret, algorithm='HS256')
    return token

def validate_session(token: str, secret: str) -> dict:
    return jwt.decode(token, secret, algorithms=['HS256'])
